var customer = {};
var sites = [];
var collections = [];
var editMode = false;
function toTitleCase(str) {
  if (!str) return str;
  return str.replace(/\w\S*/g, function (txt) {
    return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
  });
}
function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt)) return d;
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function expiryClass(d) {
  if (!d) return 'badge-neutral';
  var diff = (new Date(d) - new Date()) / (1000 * 60 * 60 * 24);
  if (diff < 0) return 'badge-danger';
  if (diff < 90) return 'badge-warn';
  return 'badge-ok';
}
function msaClass(v) {
  if (v === 'Yes') return 'badge-ok';
  if (v === 'Pending') return 'badge-warn';
  return 'badge-danger';
}
function dialClass(v) {
  if (v === 'DIAL 1') return {
    bg: '#fee2e2',
    fg: '#991b1b'
  };
  if (v === 'DIAL 2') return {
    bg: '#FAEEDA',
    fg: '#633806'
  };
  if (v === 'DIAL 3') return {
    bg: '#A3E851',
    fg: '#05042E'
  };
  return {
    bg: '#E0DFE1',
    fg: '#05042E'
  };
}
function val(id) {
  var el = document.getElementById(id);
  return el ? el.value : '';
}
function set(id, v) {
  var el = document.getElementById(id);
  if (el) el.value = v || '';
}
function txt(id, v) {
  var el = document.getElementById(id);
  if (el) el.textContent = v || '—';
}
function renderView(c) {
  txt('hdr_name', c.customer_name);
  var dialHdr = document.getElementById('hdr_dial');
  var msaHdr = document.getElementById('hdr_msa');
  if (dialHdr) {
    var dc = dialClass(c.dial_ref);
    dialHdr.textContent = c.dial_ref || '';
    dialHdr.style.display = c.dial_ref ? 'inline-block' : 'none';
    dialHdr.style.background = dc.bg;
    dialHdr.style.color = dc.fg;
    dialHdr.className = 'badge';
  }
  if (msaHdr) {
    msaHdr.textContent = c.msa_signed || '';
    msaHdr.style.display = c.msa_signed ? 'inline-block' : 'none';
    msaHdr.className = 'badge ' + msaClass(c.msa_signed);
  }
  txt('v_customer_name', c.customer_name);
  txt('v_contact_name', c.contact_name);
  txt('v_job_title', c.job_title);
  txt('v_contact_number', c.contact_number);
  txt('v_email', c.email);
  var dialEl = document.getElementById('v_dial_rating');
  if (dialEl) {
    var dc2 = dialClass(c.dial_ref);
    dialEl.innerHTML = c.dial_ref ? '<span style="font-size:11px;font-weight:700;padding:3px 10px;border-radius:20px;background:' + dc2.bg + ';color:' + dc2.fg + '">' + c.dial_ref + '</span>' : '<span style="color:#b0aeb8;font-size:13px">—</span>';
  }
  var expEl = document.getElementById('v_dial_expiry');
  if (expEl) {
    expEl.textContent = fmt(c.dial_expiry);
    var ec = expiryClass(c.dial_expiry);
    expEl.style.color = ec === 'badge-danger' ? '#991b1b' : ec === 'badge-warn' ? '#b45309' : '#085041';
  }
  var msaBadge = document.getElementById('v_msa_badge');
  if (msaBadge) {
    var mc = msaClass(c.msa_signed);
    var cols = mc === 'badge-ok' ? {
      bg: '#A3E851',
      fg: '#05042E'
    } : mc === 'badge-warn' ? {
      bg: '#FAEEDA',
      fg: '#633806'
    } : {
      bg: '#fee2e2',
      fg: '#991b1b'
    };
    msaBadge.innerHTML = c.msa_signed ? '<span style="font-size:11px;font-weight:700;padding:3px 10px;border-radius:20px;background:' + cols.bg + ';color:' + cols.fg + '">' + c.msa_signed + '</span>' : '<span style="color:#b0aeb8;font-size:13px">—</span>';
  }
  txt('v_account_manager', c.account_manager);
  var iw = document.getElementById('v_instructions_wrap');
  if (iw) {
    iw.style.display = c.default_instructions ? 'block' : 'none';
    txt('v_default_instructions', c.default_instructions);
  }
}
function populateEditForm(c) {
  set('e_customer_name', c.customer_name);
  set('e_contact_name', c.contact_name);
  set('e_job_title', c.job_title);
  set('e_contact_number', c.contact_number);
  set('e_email', c.email);
  set('e_dial_rating', c.dial_ref);
  set('e_dial_expiry', c.dial_expiry ? c.dial_expiry.substring(0, 10) : '');
  set('e_msa', c.msa_signed);
  set('e_account_manager', c.account_manager);
  set('e_default_instructions', c.default_instructions);
}
function renderSites(list) {
  var tbody = document.getElementById('sites_body');
  if (!tbody) return;
  if (!Array.isArray(list)) list = [];
  if (!list.length) {
    tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;padding:2rem;color:#888780;font-size:12px">No sites on record</td></tr>';
    return;
  }
  tbody.innerHTML = list.map(function (s) {
    var addr = [s.address1, s.city, s.postcode].filter(Boolean).join(', ');
    var hasSurvey = s.survey_id;
    var surveyBadge = hasSurvey ? '<span class="badge badge-ok">Current</span>' : '<span class="badge badge-danger">No survey</span>';
    var reviewDue = hasSurvey ? fmt(s.last_reviewed_date) : '—';
    return '<tr><td>' + addr + '</td><td>' + (s.site_contact || '—') + '</td><td>' + surveyBadge + '</td><td>' + reviewDue + '</td>' + '<td><button class="view-btn" onclick="window.viewSite(' + JSON.stringify(s).replace(/"/g, "&quot;") + ')" title="View site"><i class="ti ti-arrow-right" style="font-size:12px"></i></button></td></tr>';
  }).join('');
}
function renderCollections(list) {
  var tbody = document.getElementById('collections_body');
  if (!tbody) return;
  if (!Array.isArray(list)) list = [];
  if (!list.length) {
    tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:2rem;color:#888780;font-size:12px">No collections on record</td></tr>';
    return;
  }
  tbody.innerHTML = list.map(function (c) {
    var sc = {
      Booked: 'badge-neutral',
      Collected: 'badge-ok',
      Processing: 'badge-warn',
      Complete: 'badge-ok',
      Cancelled: 'badge-danger'
    }[c.status] || 'badge-neutral';
    return '<tr>' + '<td><span class="collection-ref">' + (c.collection_id || '') + '</span></td>' + '<td>' + fmt(c.collection_date) + '</td>' + '<td>' + (c.address1 || '—') + '</td>' + '<td><span class="badge ' + sc + '">' + (c.status || '—') + '</span></td>' + '<td>' + (c.asset_count || '0') + '</td>' + '<td><button class="view-btn" onclick="window.viewCollection(' + c.collection_id + ')" title="View"><i class="ti ti-arrow-right" style="font-size:12px"></i></button></td>' + '</tr>';
  }).join('');
}
window.setTab = function (name) {
  var tabs = ['details', 'sites', 'collections'];
  document.querySelectorAll('.tab').forEach(function (t, i) {
    t.className = i === tabs.indexOf(name) ? 'tab active' : 'tab';
  });
  tabs.forEach(function (t) {
    document.getElementById('tab_' + t).className = t === name ? 'tab-content active' : 'tab-content';
  });
};
window.toggleEdit = function () {
  editMode = !editMode;
  document.getElementById('view_mode').style.display = editMode ? 'none' : 'block';
  document.getElementById('edit_mode').style.display = editMode ? 'block' : 'none';
  var btn = document.getElementById('edit_btn');
  if (editMode) {
    populateEditForm(customer);
    btn.innerHTML = '<i class="ti ti-x" style="font-size:11px;margin-right:4px"></i>Cancel';
  } else {
    btn.innerHTML = '<i class="ti ti-edit" style="font-size:11px;margin-right:4px"></i>Edit';
  }
};
window.cancelEdit = function () {
  editMode = false;
  document.getElementById('view_mode').style.display = 'block';
  document.getElementById('edit_mode').style.display = 'none';
  document.getElementById('edit_btn').innerHTML = '<i class="ti ti-edit" style="font-size:11px;margin-right:4px"></i>Edit';
};
window.saveDetails = function () {
  appsmith.updateModel({
    customer_name: toTitleCase(val('e_customer_name')),
    contact_name: toTitleCase(val('e_contact_name')),
    job_title: toTitleCase(val('e_job_title')),
    contact_number: val('e_contact_number'),
    email: val('e_email').toLowerCase(),
    dial_rating: val('e_dial_rating'),
    dial_expiry: val('e_dial_expiry') || null,
    msa_signed: val('e_msa'),
    account_manager: val('e_account_manager'),
    default_instructions: val('e_default_instructions')
  });
  appsmith.triggerEvent('onSaveCustomer');
};
window.goBack = function () {
  appsmith.triggerEvent('onGoBack');
};
window.openSiteForm = function () {
  document.getElementById('site_form').classList.add('open');
};
window.closeSiteForm = function () {
  document.getElementById('site_form').classList.remove('open');
};
window.saveSite = function () {
  appsmith.updateModel({
    address1: toTitleCase(val('sf_address1')),
    address2: toTitleCase(val('sf_address2')),
    city: toTitleCase(val('sf_city')),
    postcode: val('sf_postcode').toUpperCase(),
    site_contact: toTitleCase(val('sf_site_contact')),
    site_phone: val('sf_phone'),
    site_email: val('sf_email').toLowerCase()
  });
  appsmith.triggerEvent('onSaveSite');
};
window.viewSite = function (s) {
  appsmith.updateModel({
    selected_site: s
  });
  appsmith.triggerEvent('onViewSite');
};
window.viewCollection = function (id) {
  appsmith.updateModel({
    selected_collection_id: id
  });
  appsmith.triggerEvent('onViewCollection');
};
function render(model) {
  customer = model.customer || {};
  sites = Array.isArray(model.sites) ? model.sites : [];
  collections = Array.isArray(model.collections) ? model.collections : [];
  renderView(customer);
  renderSites(sites);
  renderCollections(collections);
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

