    site_email: val('sf_email').toLowerCase()
  });
  appsmith.triggerEvent('onSaveSite');
};

window.viewSite = function(s) {
  appsmith.updateModel({ selected_site: s });
  appsmith.triggerEvent('onViewSite');
};

window.viewCollection = function(id) {
  appsmith.updateModel({ selected_collection_id: id });
  appsmith.triggerEvent('onViewCollection');
};

function render(model) {
  customer = model.customer || {};
  sites = Array.isArray(model.sites) ? model.sites : [];
  collections = Array.isArray(model.collections) ? model.collections : [];
  renderView(customer);
  renderSites(sites);
  renderCollections(collections);
}

appsmith.onReady(function() { render(appsmith.model); });
appsmith.onModelChange(function(model) { render(model); });
